CREATE TABLE IF NOT EXISTS "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "users" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(50) NOT NULL UNIQUE, "full_name" varchar(100) NOT NULL, "role" varchar(20) NOT NULL, "is_active" bool NOT NULL, "is_staff" bool NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "users_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "users_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "blacklisted_tokens" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "token" varchar(500) NOT NULL UNIQUE, "blacklisted_at" datetime NOT NULL, "user_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "ip_address" char(39) NULL, "user_agent" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "clients" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(100) NOT NULL, "phone" varchar(20) NOT NULL, "address" text NOT NULL, "credit_balance" decimal NOT NULL, "client_type" varchar(10) NOT NULL, "notes" text NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "is_active" bool NOT NULL);
CREATE TABLE IF NOT EXISTS "suppliers" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(100) NOT NULL, "phone" varchar(20) NOT NULL, "address" text NOT NULL, "notes" text NOT NULL, "is_active" bool NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "inputs" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "type" varchar(20) NOT NULL, "amount" decimal NOT NULL, "description" text NOT NULL, "reference" varchar(50) NOT NULL UNIQUE, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "created_by_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "order_id" bigint NULL REFERENCES "orders" ("id") DEFERRABLE INITIALLY DEFERRED, "date" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "order_outputs" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "order_id" bigint NOT NULL REFERENCES "orders" ("id") DEFERRABLE INITIALLY DEFERRED, "amount" decimal NOT NULL, "description" text NOT NULL, "type" varchar(30) NOT NULL, "created_by_output_id" bigint NULL REFERENCES "outputs" ("id") DEFERRABLE INITIALLY DEFERRED, "created_by_stock_movement_id" bigint NULL REFERENCES "stock_movements" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "outputs" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "type" varchar(30) NOT NULL, "description" text NOT NULL, "reference" varchar(50) NOT NULL, "date" datetime NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "created_by_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "order_id" bigint NULL REFERENCES "orders" ("id") DEFERRABLE INITIALLY DEFERRED, "source_input_id" bigint NOT NULL REFERENCES "inputs" ("id") DEFERRABLE INITIALLY DEFERRED, "supplier_id" bigint NULL REFERENCES "suppliers" ("id") DEFERRABLE INITIALLY DEFERRED, "product_id" bigint NULL REFERENCES "products" ("id") DEFERRABLE INITIALLY DEFERRED, "amount" decimal NOT NULL);
CREATE TABLE IF NOT EXISTS "stock_movements" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "movement_type" varchar(3) NOT NULL, "quantity" decimal NOT NULL, "date" datetime NOT NULL, "created_at" datetime NOT NULL, "created_by_id" bigint NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "order_id" bigint NULL REFERENCES "orders" ("id") DEFERRABLE INITIALLY DEFERRED, "product_id" bigint NOT NULL REFERENCES "products" ("id") DEFERRABLE INITIALLY DEFERRED, "price" decimal NOT NULL, "created_by_output_id" bigint NULL REFERENCES "outputs" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "orders" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "order_number" varchar(50) NOT NULL UNIQUE, "total_amount" decimal NOT NULL, "status" varchar(20) NOT NULL, "description" text NOT NULL, "delivery_date" date NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "client_id" bigint NOT NULL REFERENCES "clients" ("id") DEFERRABLE INITIALLY DEFERRED, "order_date" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "products" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(100) NOT NULL, "unit" varchar(20) NOT NULL, "current_quantity" decimal NOT NULL, "description" text NOT NULL, "is_active" bool NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "reference" varchar(100) NOT NULL UNIQUE);
